+/**
+ * Benchmark: Eager Materialization — VectorJSON vs JSON.parse
+ *
+ * Tests shape-aware constructor caching + key interning.
+ * Usage: bun bench/eager-vs-json.mjs
+ */
+import { readFileSync, existsSync } from "node:fs";
+import { join, dirname } from "node:path";
+import { fileURLToPath } from "node:url";
+import { init } from "../dist/index.js";
+
+const __dirname = dirname(fileURLToPath(import.meta.url));
+
+function bench(fn, { warmup = 100, durationMs = 3000 } = {}) {
+  for (let i = 0; i < warmup; i++) fn();
+  let ops = 0;
+  const start = performance.now();
+  const deadline = start + durationMs;
+  while (performance.now() < deadline) { fn(); ops++; }
+  const elapsed = performance.now() - start;
+  return { ops, opsPerSec: (ops / elapsed) * 1000, meanMs: elapsed / ops };
+}
+
+function fmt(ms) {
+  if (ms < 0.001) return (ms * 1e6).toFixed(0) + " ns";
+  if (ms < 1) return (ms * 1e3).toFixed(1) + " µs";
+  return ms.toFixed(2) + " ms";
+}
+
+async function run() {
+  const vj = await init();
+
+  // Generate homogeneous test data (typical API response)
+  const homogeneous = JSON.stringify({
+    data: Array.from({ length: 1000 }, (_, i) => ({
+      id: i,
+      name: `user_${i}`,
+      email: `user${i}@example.com`,
+      active: i % 2 === 0,
+      score: Math.random() * 100,
+    })),
+  });
+
+  // Generate heterogeneous test data (varied shapes)
+  const heterogeneous = JSON.stringify({
+    users: Array.from({ length: 200 }, (_, i) => ({
+      id: i,
+      name: `user_${i}`,
+      ...(i % 2 === 0 ? { email: `u${i}@x.com` } : {}),
+      ...(i % 3 === 0 ? { role: "admin" } : {}),
+      ...(i % 5 === 0 ? { tags: ["a", "b"] } : {}),
+    })),
+    settings: { theme: "dark", lang: "en" },
+    meta: { total: 200, page: 1 },
+  });
+
+  // Load fixture files if available
+  const fixtures = {};
+  for (const name of ["small", "medium", "large"]) {
+    const path = join(__dirname, "fixtures", `${name}.json`);
+    if (existsSync(path)) {
+      fixtures[name] = readFileSync(path, "utf-8");
+    }
+  }
+
+  console.log("\n╔═══════════════════════════════════════════════════════════════════╗");
+  console.log("║        Eager Materialization — Shape-Aware Constructors          ║");
+  console.log("╚═══════════════════════════════════════════════════════════════════╝\n");
+
+  const tests = [
+    ["homogeneous (1000 same-shape objs)", homogeneous],
+    ["heterogeneous (varied shapes)", heterogeneous],
+    ...Object.entries(fixtures).map(([name, data]) => [`fixture: ${name}.json (${(data.length / 1024).toFixed(1)}KB)`, data]),
+  ];
+
+  for (const [label, json] of tests) {
+    console.log(`  ─── ${label} ───`);
+
+    // JSON.parse
+    const jp = bench(() => JSON.parse(json));
+    console.log(`  ${"JSON.parse".padEnd(35)} ${fmt(jp.meanMs).padStart(10)}  (${jp.opsPerSec.toFixed(0)} ops/s)`);
+
+    // VectorJSON eager
+    const ve = bench(() => vj.parse(json, { mode: "eager" }));
+    console.log(`  ${"VectorJSON eager".padEnd(35)} ${fmt(ve.meanMs).padStart(10)}  (${ve.opsPerSec.toFixed(0)} ops/s)`);
+
+    // VectorJSON lazy (for reference)
+    const vl = bench(() => vj.parse(json));
+    console.log(`  ${"VectorJSON lazy (no materialize)".padEnd(35)} ${fmt(vl.meanMs).padStart(10)}  (${vl.opsPerSec.toFixed(0)} ops/s)`);
+
+    // VectorJSON lazy + full materialize (simulate eager via lazy + JSON.stringify)
+    const vm = bench(() => {
+      const r = vj.parse(json);
+      const m = vj.materialize(r);
+      return m;
+    });
+    console.log(`  ${"VectorJSON lazy+materialize".padEnd(35)} ${fmt(vm.meanMs).padStart(10)}  (${vm.opsPerSec.toFixed(0)} ops/s)`);
+
+    const ratio = ve.meanMs / jp.meanMs;
+    console.log(`  → eager vs JSON.parse: ${ratio.toFixed(2)}x ${ratio <= 1 ? "FASTER ✅" : "slower"}\n`);
+  }
+
+  // Repeated parse benchmark (tests constructor cache warmth)
+  console.log("╔═══════════════════════════════════════════════════════════════════╗");
+  console.log("║       Repeated Parse (Same Shape — Constructor Cache Warm)       ║");
+  console.log("╚═══════════════════════════════════════════════════════════════════╝\n");
+
+  const small = JSON.stringify({ id: 1, name: "Alice", email: "a@b.com", active: true });
+  console.log(`  ─── small object: ${small} ───`);
+
+  const jpSmall = bench(() => JSON.parse(small), { warmup: 1000, durationMs: 3000 });
+  console.log(`  ${"JSON.parse".padEnd(35)} ${fmt(jpSmall.meanMs).padStart(10)}  (${jpSmall.opsPerSec.toFixed(0)} ops/s)`);
+
+  const veSmall = bench(() => vj.parse(small, { mode: "eager" }), { warmup: 1000, durationMs: 3000 });
+  console.log(`  ${"VectorJSON eager (cached ctor)".padEnd(35)} ${fmt(veSmall.meanMs).padStart(10)}  (${veSmall.opsPerSec.toFixed(0)} ops/s)`);
+
+  const ratioSmall = veSmall.meanMs / jpSmall.meanMs;
+  console.log(`  → ratio: ${ratioSmall.toFixed(2)}x ${ratioSmall <= 1 ? "FASTER ✅" : "slower"}\n`);
+}
+
+run().catch(e => { console.error(e); process.exit(1); });

@@ -828,6 +828,62 @@ export async function init(options?: {
   // One WASM call produces the buffer, then JS reads it linearly — zero
   // TextDecoder, zero FFI calls needed.

+  // --- String key interning ---
+  // Reusing the same string reference for repeated keys (e.g. "id" in 1000 objects)
+  // lets V8 use pointer comparison for hidden class transition lookups instead of
+  // character-by-character comparison. This is critical for monomorphic IC.
+  const keyIntern = new Map<string, string>();
+  function internKey(raw: string): string {
+    let s = keyIntern.get(raw);
+    if (s === undefined) { s = raw; keyIntern.set(s, s); }
+    return s;
+  }
+
+  // --- Shape-aware constructor caching ---
+  // For arrays of same-shaped objects, we cache a constructor per shape.
+  // V8 scans constructor bodies for `this[...]=` assignments and pre-allocates
+  // in-object property slots — zero hidden class transitions per construction.
+  // The constructor takes a single array argument to avoid argument count limits.
+  const shapeCtors = new Map<string, { ctor: new (vals: unknown[]) => Record<string, unknown>; keys: string[] }>();
+  const MAX_SHAPE_CACHE = 256;
+
+  // Last-shape fast path: consecutive same-shaped objects (e.g. array of 1000
+  // API response items) skip the join() + Map.get() entirely via pointer-equal
+  // interned key comparison.
+  let lastShapeKeys: string[] = [];
+  let lastShapeCtor: (new (vals: unknown[]) => Record<string, unknown>) | null = null;
+
+  function matchLastShape(keys: string[]): boolean {
+    if (keys.length !== lastShapeKeys.length) return false;
+    for (let i = 0; i < keys.length; i++) {
+      if (keys[i] !== lastShapeKeys[i]) return false; // pointer compare (interned)
+    }
+    return true;
+  }
+
+  function getShapeCtor(keys: string[]): new (vals: unknown[]) => Record<string, unknown> {
+    // Fast path: same shape as last object (very common in arrays)
+    if (lastShapeCtor && matchLastShape(keys)) return lastShapeCtor;
+
+    const shapeKey = keys.join('\x00');
+    const cached = shapeCtors.get(shapeKey);
+    if (cached) {
+      lastShapeKeys = cached.keys;
+      lastShapeCtor = cached.ctor;
+      return cached.ctor;
+    }
+    // Evict entire cache if too large (heterogeneous data)
+    if (shapeCtors.size >= MAX_SHAPE_CACHE) shapeCtors.clear();
+    // Build constructor: this["id"]=a[0];this["name"]=a[1];...
+    const body = keys.map((k, i) => `this[${JSON.stringify(k)}]=a[${i}]`).join(';');
+    const ctor = new Function('a', body) as unknown as new (vals: unknown[]) => Record<string, unknown>;
+    const frozenKeys = keys.slice();
+    shapeCtors.set(shapeKey, { ctor, keys: frozenKeys });
+    lastShapeKeys = frozenKeys;
+    lastShapeCtor = ctor;
+    return ctor;
+  }
+
   // Read a UTF-16LE string from the materialization buffer.
   // Format: [u32 char_count][pad?][...utf16le code units]
   // A 1-byte alignment pad exists when the offset after char_count is odd.
